#include <stdio.h>
#include <stdlib.h>
#define MAXN 1005
int parent[MAXN], rank[MAXN];
int find(int x) {
    if (parent[x] != x) parent[x] = find(parent[x]);
    return parent[x];
}
void unionSet(int x, int y) {
    int rootx = find(x), rooty = find(y);
    if (rootx != rooty) {
        if (rank[rootx] > rank[rooty]) parent[rooty] = rootx;
        else if (rank[rootx] < rank[rooty]) parent[rootx] = rooty;
        else {
            parent[rooty] = rootx;
            rank[rootx]++;
        }
    }
}
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    for (int i = 1; i <= N; i++) {
        parent[i] = i;
        rank[i] = 0;
    }
    for (int i = 0; i < M; i++) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        unionSet(X, Y);
        int count = 0;
        for (int j = 1; j <= N; j++) {
            for (int k = j + 1; k <= N; k++) {
                if (find(j) != find(k)) count++;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

